export enum DistributionType {
  UNIFORM = '均匀分布',
  EXPONENTIAL = '指数分布',
  NORMAL = '正态分布',
  BIMODAL = '双峰分布'
}

export interface SimulationResult {
  parentData: number[];
  samplingMeans: number[];
  theoreticalMean: number;
  theoreticalStd: number;
  observedMean: number;
  observedStd: number;
}

export interface ChartDataItem {
  bin: string;
  count: number;
}

import { GoogleGenAI } from "@google/genai";
import { DistributionType } from "../types";

export async function getStatisticalInsight(
  distType: DistributionType,
  sampleSize: number,
  numSamples: number,
  observedMean: number,
  observedStd: number
): Promise<string> {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const prompt = `
    作为一名资深统计学教授，请分析以下中心极限定理（CLT）的实验结果：
    - 总体分布类型：${distType}
    - 样本容量 (n)：${sampleSize}
    - 模拟实验次数：${numSamples}
    - 实验观测到的均值均值：${observedMean.toFixed(4)}
    - 实验观测到的均值标准差：${observedStd.toFixed(4)}

    请根据这些参数提供以下深度洞察：
    1. 解释为什么当前结果符合（或不完全符合）中心极限定理。
    2. 针对当前的样本容量 n=${sampleSize}，说明其对分布形态正态化的影响。
    3. 给学习者一个关于统计学直觉的建议。

    请使用专业且鼓励性的中文回答，字数控制在200字以内，使用Markdown格式。
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        temperature: 0.7,
        thinkingConfig: { thinkingBudget: 0 }
      }
    });
    return response.text || "无法获取AI洞察。";
  } catch (error) {
    console.error("AI Insight Error:", error);
    return "获取AI分析时出错，请稍后重试。";
  }
}

import { DistributionType } from '../types';

export const generateParentData = (type: DistributionType, count: number): number[] => {
  const data: number[] = [];
  for (let i = 0; i < count; i++) {
    switch (type) {
      case DistributionType.UNIFORM:
        data.push(Math.random());
        break;
      case DistributionType.EXPONENTIAL:
        data.push(-Math.log(1 - Math.random()));
        break;
      case DistributionType.NORMAL:
        data.push(boxMullerTransform());
        break;
      case DistributionType.BIMODAL:
        data.push(Math.random() > 0.5 ? boxMullerTransform() * 0.5 - 2 : boxMullerTransform() * 0.5 + 2);
        break;
    }
  }
  return data;
};

const boxMullerTransform = (): number => {
  let u = 0, v = 0;
  while (u === 0) u = Math.random();
  while (v === 0) v = Math.random();
  return Math.sqrt(-2.0 * Math.log(u)) * Math.cos(2.0 * Math.PI * v);
};

export const runSimulation = (
  type: DistributionType,
  sampleSize: number,
  numSamples: number
) => {
  const samplingMeans: number[] = [];

  for (let i = 0; i < numSamples; i++) {
    const sample = generateParentData(type, sampleSize);
    const mean = sample.reduce((a, b) => a + b, 0) / sampleSize;
    samplingMeans.push(mean);
  }

  const observedMean = samplingMeans.reduce((a, b) => a + b, 0) / numSamples;
  const observedVar = samplingMeans.reduce((a, b) => a + (b - observedMean) ** 2, 0) / numSamples;

  return {
    samplingMeans,
    observedMean,
    observedStd: Math.sqrt(observedVar)
  };
};

export const binData = (data: number[], binCount: number = 30) => {
  if (data.length === 0) return [];
  const min = Math.min(...data);
  const max = Math.max(...data);
  const range = max - min;
  const step = range / binCount;

  const bins = Array(binCount).fill(0);
  data.forEach(val => {
    const index = Math.min(Math.floor((val - min) / step), binCount - 1);
    bins[index]++;
  });

  return bins.map((count, i) => ({
    bin: (min + i * step).toFixed(2),
    count
  }));
};

import React from 'react';
import { 
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, AreaChart, Area 
} from 'recharts';
import { binData } from '../utils/statistics';

interface Props {
  data: number[];
  title: string;
  color: string;
}

const DistributionChart: React.FC<Props> = ({ data, title, color }) => {
  const binned = binData(data, 40);

  return (
    <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 h-80 flex flex-col">
      <h3 className="text-sm font-semibold text-slate-500 mb-4 uppercase tracking-wider">{title}</h3>
      <div className="flex-1 w-full">
        <ResponsiveContainer width="100%" height="100%">
          <AreaChart data={binned}>
            <defs>
              <linearGradient id={`gradient-${color}`} x1="0" y1="0" x2="0" y2="1">
                <stop offset="5%" stopColor={color} stopOpacity={0.3}/>
                <stop offset="95%" stopColor={color} stopOpacity={0}/>
              </linearGradient>
            </defs>
            <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
            <XAxis 
              dataKey="bin" 
              fontSize={10} 
              tick={{fill: '#94a3b8'}} 
              axisLine={{stroke: '#e2e8f0'}}
            />
            <YAxis hide />
            <Tooltip 
              contentStyle={{ borderRadius: '12px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)' }}
              labelClassName="text-slate-600 font-medium"
            />
            <Area 
              type="monotone" 
              dataKey="count" 
              stroke={color} 
              fillOpacity={1} 
              fill={`url(#gradient-${color})`} 
              strokeWidth={2}
              animationDuration={1000}
            />
          </AreaChart>
        </ResponsiveContainer>
      </div>
    </div>
  );
};

export default DistributionChart;

