export enum DistributionType {
  UNIFORM = '均匀分布',
  EXPONENTIAL = '指数分布',
  NORMAL = '正态分布',
  BIMODAL = '双峰分布',
  BINOMIAL = '二项分布',
  POISSON = '泊松分布'
}

export interface SimulationResult {
  parentData: number[];
  samplingMeans: number[];
  theoreticalMean: number;
  theoreticalStd: number;
  observedMean: number;
  observedStd: number;
}

export interface ChartDataItem {
  bin: string;
  count: number;
}

export type AIModelType = 'gemini-3-flash-preview' | 'deepseek-chat';

import { DistributionType } from '../types';

export const generateParentData = (type: DistributionType, count: number): number[] => {
  const data: number[] = [];
  for (let i = 0; i < count; i++) {
    switch (type) {
      case DistributionType.UNIFORM:
        data.push(Math.random());
        break;
      case DistributionType.EXPONENTIAL:
        data.push(-Math.log(1 - Math.random()));
        break;
      case DistributionType.NORMAL:
        data.push(boxMullerTransform());
        break;
      case DistributionType.BIMODAL:
        data.push(Math.random() > 0.5 ? boxMullerTransform() * 0.5 - 2 : boxMullerTransform() * 0.5 + 2);
        break;
      case DistributionType.BINOMIAL:
        // Using n=20, p=0.5 as a representative Binomial distribution
        let successes = 0;
        const n = 20;
        const p = 0.5;
        for (let j = 0; j < n; j++) {
          if (Math.random() < p) successes++;
        }
        data.push(successes);
        break;
      case DistributionType.POISSON:
        // Using lambda=4
        const lambda = 4;
        const L = Math.exp(-lambda);
        let k = 0;
        let prob = 1;
        do {
          k++;
          prob *= Math.random();
        } while (prob > L);
        data.push(k - 1);
        break;
    }
  }
  return data;
};

const boxMullerTransform = (): number => {
  let u = 0, v = 0;
  while (u === 0) u = Math.random();
  while (v === 0) v = Math.random();
  return Math.sqrt(-2.0 * Math.log(u)) * Math.cos(2.0 * Math.PI * v);
};

export const runSimulation = (
  type: DistributionType,
  sampleSize: number,
  numSamples: number
) => {
  const samplingMeans: number[] = [];

  for (let i = 0; i < numSamples; i++) {
    const sample = generateParentData(type, sampleSize);
    const mean = sample.reduce((a, b) => a + b, 0) / sampleSize;
    samplingMeans.push(mean);
  }

  const observedMean = samplingMeans.reduce((a, b) => a + b, 0) / numSamples;
  const observedVar = samplingMeans.reduce((a, b) => a + (b - observedMean) ** 2, 0) / numSamples;

  return {
    samplingMeans,
    observedMean,
    observedStd: Math.sqrt(observedVar)
  };
};

export const binData = (data: number[], binCount: number = 30) => {
  if (data.length === 0) return [];
  const min = Math.min(...data);
  const max = Math.max(...data);
  const range = max - min;
  const step = range === 0 ? 1 : range / binCount;

  const bins = Array(binCount).fill(0);
  data.forEach(val => {
    const index = Math.min(Math.floor((val - min) / step), binCount - 1);
    bins[index >= 0 ? index : 0]++;
  });

  return bins.map((count, i) => ({
    bin: (min + i * step).toFixed(2),
    count
  }));
};

