import { GoogleGenAI } from "@google/genai";
import { DistributionType } from "../types";

export async function getStatisticalInsight(
  distType: DistributionType,
  sampleSize: number,
  numSamples: number,
  observedMean: number,
  observedStd: number,
  apiKey: string
): Promise<string> {
  const ai = new GoogleGenAI({ apiKey: apiKey });

  const prompt = `
    作为一名资深统计学教授，请分析以下中心极限定理（CLT）的实验结果：
    - 总体分布类型：${distType}
    - 样本容量 (n)：${sampleSize}
    - 模拟实验次数：${numSamples}
    - 实验观测到的均值均值：${observedMean.toFixed(4)}
    - 实验观测到的均值标准差：${observedStd.toFixed(4)}

    请根据这些参数提供以下深度洞察：
    1. 解释为什么当前结果符合（或不完全符合）中心极限定理。
    2. 针对当前的样本容量 n=${sampleSize}，说明其对分布形态正态化的影响。
    3. 给学习者一个关于统计学直觉的建议。

    请使用专业且鼓励性的中文回答，字数控制在200字以内，使用Markdown格式。
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        temperature: 0.7,
        thinkingConfig: { thinkingBudget: 0 }
      }
    });
    return response.text || "无法获取AI洞察。";
  } catch (error) {
    console.error("AI Insight Error:", error);
    if (error instanceof Error && error.message.includes("API key")) {
        return "API Key 无效或未授权，请检查设置。";
    }
    return "获取AI分析时出错，请稍后重试。";
  }
}

