                  <input type="password" placeholder="Gemini Key" value={geminiKey} onChange={e=>setGeminiKey(e.target.value)} className="w-full bg-white/10 border border-white/20 rounded-xl px-4 py-2.5 text-sm mb-3 focus:ring-1 focus:ring-white/50 outline-none text-white placeholder:text-white/40" />
                  <input type="password" placeholder="DeepSeek Key" value={deepseekKey} onChange={e=>setDeepseekKey(e.target.value)} className="w-full bg-white/10 border border-white/20 rounded-xl px-4 py-2.5 text-sm mb-5 focus:ring-1 focus:ring-white/50 outline-none text-white placeholder:text-white/40" />
                  <button onClick={saveKeys} className="w-full bg-white text-indigo-600 py-3 rounded-xl text-sm font-bold shadow-xl hover:bg-indigo-50 transition-colors">锁定连接配置</button>
                </div>
              </div>
            ) : (
              <div className="flex flex-col h-full z-10">
                <div className="flex-1 overflow-y-auto pr-2 space-y-4 scrollbar-hide">
                  {(savedGeminiKey || savedDeepseekKey) && chatHistory.length === 0 && (
                    <div className="animate-fade-in space-y-4">
                      <div className="p-4 bg-white/10 rounded-2xl border border-white/20 backdrop-blur-sm">
                         <p className="text-[10px] font-bold text-white/70 uppercase mb-3 tracking-widest">Step 2: 模型引擎</p>
                         <div className="grid grid-cols-2 gap-2">
                           {savedGeminiKey && <button onClick={()=>setSelectedModel('gemini-3-flash-preview')} className={`py-2 rounded-lg text-xs font-bold border transition-all ${selectedModel==='gemini-3-flash-preview'?'bg-white text-indigo-600 shadow-lg':'border-white/20 hover:bg-white/5'}`}>Gemini 3</button>}
                           {savedDeepseekKey && <button onClick={()=>setSelectedModel('deepseek-chat')} className={`py-2 rounded-lg text-xs font-bold border transition-all ${selectedModel==='deepseek-chat'?'bg-white text-indigo-600 shadow-lg':'border-white/20 hover:bg-white/5'}`}>DeepSeek</button>}
                         </div>
                      </div>
                      {selectedModel && (
                        <div className="animate-slide-in">
                          <p className="text-[10px] font-bold text-white/70 uppercase mb-3 tracking-widest">Step 3: 统计洞察</p>
                          <div className="space-y-2">
                            {["深度评估正态性", "解释 SE 递减规律"].map(opt => (
                              <button key={opt} onClick={()=>handleAskAi(opt)} className="w-full text-left text-xs p-3.5 bg-white/10 rounded-2xl border border-white/10 hover:bg-white/20 transition-colors font-medium">专家视角：{opt}</button>
                            ))}
                          </div>
                        </div>
                      )}
                    </div>
                  )}

                  {chatHistory.map((m,i)=>(
                    <div key={i} className={`flex ${m.role==='user'?'justify-end':'justify-start'}`}>
                      <div className={`max-w-[85%] p-3.5 rounded-2xl text-[13px] leading-relaxed shadow-sm ${m.role==='user'?'bg-white text-indigo-600 rounded-tr-none':'bg-white/20 text-white rounded-tl-none border border-white/10 prose-invert font-medium'}`}>
                        {m.text}
                      </div>
                    </div>
                  ))}
                  {isAiLoading && <div className="p-4 bg-white/10 rounded-2xl animate-pulse text-[11px] font-bold text-white/70 flex items-center gap-2">
                    <div className="w-1.5 h-1.5 bg-white rounded-full animate-bounce"></div>
                    统计学者正在演算...
                  </div>}
                  <div ref={chatEndRef}></div>
                </div>

                {selectedModel && (
                  <div className="mt-4 pt-4 border-t border-white/20 relative">
                    <input type="text" value={userInput} onChange={e=>setUserInput(e.target.value)} onKeyDown={e=>e.key==='Enter'&&handleAskAi()} placeholder="输入您的统计学疑问..." className="w-full bg-white/10 rounded-2xl px-5 py-4 text-sm outline-none focus:ring-2 focus:ring-white/40 pr-12 text-white placeholder:text-white/40" />
                    <button onClick={()=>handleAskAi()} className="absolute right-2 top-[24px] p-2 text-white/80 hover:text-white transition-colors"><svg className="w-6 h-6" fill="currentColor" viewBox="0 0 24 24"><path d="M2.01 21L23 12L2.01 3L2 10l15 2l-15 2z"/></svg></button>
                  </div>
                )}
              </div>
            )}
            <div className="absolute -top-20 -left-20 w-40 h-40 bg-white/20 blur-3xl rounded-full pointer-events-none"></div>
          </div>
        </aside>

        {/* 右侧主视窗 */}
        <section className="lg:col-span-8 space-y-8">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <DistributionChart data={parentData} title="总体概率密度分布" color="#6366f1" />
            <DistributionChart data={samplingMeans} title={`抽样均值分布 (n=${sampleSize})`} color="#10b981" />
          </div>

          <div className="bg-white/80 backdrop-blur-sm p-8 rounded-3xl shadow-sm border border-white">
            <h3 className="text-sm font-bold text-slate-400 uppercase tracking-widest mb-8 flex items-center justify-between">
              实时统计摘要
              <div className="flex gap-4">
                <span className="text-[11px] bg-slate-100 px-2 py-0.5 rounded text-slate-500 font-mono">μ理论: {theoretical.mu.toFixed(2)}</span>
                <span className="text-[11px] bg-slate-100 px-2 py-0.5 rounded text-slate-500 font-mono">σ理论: {theoretical.sigma.toFixed(2)}</span>
              </div>
            </h3>

            <div className="grid grid-cols-1 sm:grid-cols-3 gap-8">
              <div className="space-y-1">
                <p className="text-[11px] font-bold text-slate-300 uppercase tracking-tighter">观测样本均值 X̄</p>
                <p className="text-4xl font-black text-slate-700 font-mono tracking-tighter">{stats.mean.toFixed(4)}</p>
              </div>
              <div className="space-y-1">
                <p className="text-[11px] font-bold text-slate-300 uppercase tracking-tighter">观测标准误 SE</p>
                <p className="text-4xl font-black text-emerald-500 font-mono tracking-tighter">{stats.std.toFixed(4)}</p>
              </div>
              <div className="space-y-1">
                <p className="text-[11px] font-bold text-slate-300 uppercase tracking-tighter">正态收敛评估</p>
                <p className={`text-4xl font-black tracking-tighter ${sampleSize >= 30 ? 'text-indigo-500' : 'text-amber-400'}`}>
                  {sampleSize >= 100 ? '卓越' : sampleSize >= 30 ? '稳健' : '初级'}
                </p>
              </div>
            </div>

            {/* 置信区间雨点图预览 - 调色为淡雅绿与灰 */}
            <div className="mt-12 pt-8 border-t border-indigo-50">
              <div className="flex justify-between items-center mb-5">
                <h4 className="text-xs font-bold text-slate-400 uppercase flex items-center gap-2">
                  <div className="w-2 h-2 bg-emerald-300 rounded-full"></div> 95% 置信区间覆盖监测 (Top 100)
                </h4>
                <div className="text-xs font-bold text-slate-400">
                  当前覆盖率: <span className={ciSuccessCount >= 90 ? 'text-emerald-500' : 'text-rose-400'}>{ciSuccessCount}%</span>
                </div>
              </div>
              <div className="h-16 w-full bg-slate-50/50 rounded-2xl flex items-center gap-[1px] px-4 border border-slate-100 overflow-hidden">
                {ciData.map((d, i) => (
                  <div key={i} className="flex-1 flex flex-col items-center justify-center h-full">
                    <div className={`w-full ${d.contains ? 'bg-emerald-300' : 'bg-rose-300'} rounded-full`} style={{ height: '30%', opacity: 0.5 }}></div>
                  </div>
                ))}
              </div>
              <p className="mt-4 text-[11px] text-slate-400 leading-relaxed font-medium">
                专家解读：随着样本量 <span className="font-mono text-indigo-500 italic">n</span> 的增加，置信区间的宽度将逐步收窄。
              </p>
            </div>
          </div>

          <TheoryModule />

          <footer className="text-center py-12 text-[10px] font-bold text-slate-300 uppercase tracking-[0.4em]">
            Center Limit Theorem Lab · Interactive Education Platform
          </footer>
        </section>
      </main>
    </div>
  );
};

export default App;

import React from 'react';
