import React, { useState, useEffect, useCallback, useRef } from 'react';
import { DistributionType, AIModelType } from './types';
import { generateParentData, runSimulation, getTheoreticalParams } from './utils/statistics';
import DistributionChart from './components/DistributionChart';
import TheoryModule from './components/TheoryModule';
import { getStatisticalInsight } from './services/geminiService';

interface Message {
  role: 'user' | 'ai';
  text: string;
}

const App: React.FC = () => {
  const [distType, setDistType] = useState<DistributionType>(DistributionType.UNIFORM);
  const [sampleSize, setSampleSize] = useState<number>(30);
  const [numSamples, setNumSamples] = useState<number>(1000);

  const [parentData, setParentData] = useState<number[]>([]);
  const [samplingMeans, setSamplingMeans] = useState<number[]>([]);
  const [ciData, setCiData] = useState<{ low: number; high: number; contains: boolean }[]>([]);
  const [stats, setStats] = useState({ mean: 0, std: 0 });

  // AI State
  const [chatHistory, setChatHistory] = useState<Message[]>([]);
  const [isAiLoading, setIsAiLoading] = useState(false);
  const [userInput, setUserInput] = useState('');
  const chatEndRef = useRef<HTMLDivElement>(null);

  // Step-based AI Settings
  const [aiApiKey, setAiApiKey] = useState('');
  const [isKeySaved, setIsKeySaved] = useState(false);
  const [selectedModel, setSelectedModel] = useState<AIModelType | null>(null);

  const scrollToBottom = () => chatEndRef.current?.scrollIntoView({ behavior: "smooth" });
  useEffect(() => { scrollToBottom(); }, [chatHistory, isAiLoading]);

  const simulate = useCallback(() => {
    const parent = generateParentData(distType, 2000);
    const result = runSimulation(distType, sampleSize, numSamples);
    setParentData(parent);
    setSamplingMeans(result.samplingMeans);
    setCiData(result.ciList);
    setStats({ mean: result.observedMean, std: result.observedStd });
  }, [distType, sampleSize, numSamples]);

  useEffect(() => { simulate(); }, [simulate]);

  const handleAskAi = async (question?: string) => {
    const query = question || userInput;
    if (!selectedModel || !query.trim() || !aiApiKey) return;

    setChatHistory(prev => [...prev, { role: 'user', text: query }]);
    if (!question) setUserInput('');
    setIsAiLoading(true);

    try {
      // 这里的 getStatisticalInsight 可以根据 selectedModel 路由到不同的模型逻辑
      const insight = await getStatisticalInsight(
        distType, sampleSize, numSamples, stats.mean, stats.std, aiApiKey, query
      );
      setChatHistory(prev => [...prev, { role: 'ai', text: insight }]);
    } catch (e) {
      setChatHistory(prev => [...prev, { role: 'ai', text: "❌ 专家系统连接异常，请检查网络或 Key 的有效性。" }]);
    } finally {
      setIsAiLoading(false);
    }
  };

  const theoretical = getTheoreticalParams(distType);
  const ciSuccessCount = ciData.filter(d => d.contains).length;

  return (
    <div className="min-h-screen bg-[#f7f9fc] text-[#4a5568] pb-20">
      <nav className="bg-white/60 backdrop-blur-xl border-b border-indigo-50/50 sticky top-0 z-50">
        <div className="max-w-7xl mx-auto px-6 h-16 flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="w-9 h-9 bg-gradient-to-tr from-[#9bb7d4] to-[#c2d4e3] rounded-xl flex items-center justify-center shadow-sm">
              <span className="text-white font-bold text-xl">Σ</span>
            </div>
            <div>
              <h1 className="text-lg font-bold leading-none text-[#2d3748]">CLT 统计实验室</h1>
              <p className="text-[10px] text-[#a0aec0] font-bold uppercase tracking-[0.2em]">Senior Academic Design</p>
            </div>
          </div>
        </div>
      </nav>

      <main className="max-w-7xl mx-auto px-6 mt-8 grid grid-cols-1 lg:grid-cols-12 gap-8">
        {/* 左侧控制与 AI 模块 */}
        <aside className="lg:col-span-4 space-y-6">
          {/* 参数设置 */}
          <div className="bg-white p-6 rounded-[2rem] shadow-sm border border-white/50">
            <h2 className="text-xs font-bold uppercase tracking-widest text-[#a0aec0] mb-6 flex items-center gap-2">
              <span className="w-1.5 h-4 bg-[#b8c6db] rounded-full"></span> 实验参数
            </h2>
            <div className="space-y-6">
              <div>
                <label className="block text-[10px] font-bold text-[#cbd5e0] mb-3 uppercase">总体分布类型</label>
                <div className="grid grid-cols-2 gap-2">
                  {Object.values(DistributionType).map(type => (
                    <button key={type} onClick={() => setDistType(type)} className={`px-3 py-2.5 rounded-xl text-xs font-semibold transition-all ${distType === type ? 'bg-[#9bb7d4] text-white shadow-md' : 'bg-[#f8fafc] text-[#718096] hover:bg-[#edf2f7] border border-[#e2e8f0]'}`}>{type}</button>
                  ))}
                </div>
              </div>
              <div className="space-y-5">
                <div>
                  <div className="flex justify-between items-end mb-2">
                    <label className="text-[10px] font-bold text-[#cbd5e0] uppercase">样本容量 n</label>
                    <span className="text-lg font-black text-[#9bb7d4]">{sampleSize}</span>
                  </div>
                  <input type="range" min="1" max="200" value={sampleSize} onChange={(e) => setSampleSize(parseInt(e.target.value))} className="w-full h-1 bg-[#e2e8f0] rounded-lg appearance-none cursor-pointer accent-[#9bb7d4]" />
                </div>
                <button onClick={simulate} className="w-full bg-[#f8fafc] text-[#718096] border border-[#e2e8f0] py-4 rounded-2xl font-bold hover:bg-[#9bb7d4] hover:text-white transition-all active:scale-[0.98]">刷新实验序列</button>
              </div>
            </div>
          </div>

          {/* AI 洞察分析 - 精致淡雅风格 */}
          <div className="bg-white p-6 rounded-[2rem] shadow-sm border border-white/50 flex flex-col h-[550px] relative overflow-hidden">
            <div className="flex justify-between items-center mb-6 z-10">
              <h3 className="text-sm font-bold text-[#4a5568] flex items-center gap-2">
                <div className="w-2 h-2 bg-[#9bb7d4] rounded-full"></div> AI 洞察分析
              </h3>
              {isKeySaved && (
                <button onClick={() => {setIsKeySaved(false); setSelectedModel(null);}} className="text-[10px] text-[#a0aec0] hover:text-[#9bb7d4] font-bold underline">重置配置</button>
              )}
            </div>

            <div className="flex-1 flex flex-col z-10 overflow-hidden">
              {!isKeySaved ? (
                // 第一步：输入 Key
                <div className="flex-1 flex flex-col justify-center animate-fade-in space-y-4">
                  <div className="text-center space-y-2">
                    <div className="w-12 h-12 bg-[#f0f4f8] rounded-full flex items-center justify-center mx-auto text-[#9bb7d4]">
                      <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15 7a2 2 0 012 2m4 0a6 6 0 01-7.743 5.743L11 17H9v2H7v2H4a1 1 0 01-1-1v-2.586a1 1 0 01.293-.707l5.964-5.964A6 6 0 1121 9z"></path></svg>
                    </div>
                    <p className="text-xs font-bold text-[#718096]">第一步：验证专家连接</p>
                    <p className="text-[10px] text-[#a0aec0]">请输入您的 API Key 以激活 AI 统计学者</p>
                  </div>
                  <input 
                    type="password" 
                    placeholder="在此粘贴您的 API-Key" 
                    value={aiApiKey} 
                    onChange={e => setAiApiKey(e.target.value)}
                    className="w-full bg-[#f8fafc] border border-[#e2e8f0] rounded-2xl px-5 py-4 text-xs outline-none focus:ring-2 focus:ring-[#9bb7d4]/20 transition-all"
                  />
                  <button 
                    disabled={!aiApiKey}
                    onClick={() => setIsKeySaved(true)}
                    className="w-full bg-[#9bb7d4] text-white py-4 rounded-2xl font-bold text-xs shadow-sm disabled:opacity-50 hover:bg-[#8aa7c4] transition-all"
                  >
                    验证并进入下一步
                  </button>
                </div>
              ) : !selectedModel ? (
                // 第二步：选择模型
                <div className="flex-1 flex flex-col justify-center animate-slide-in space-y-6">
                  <div className="text-center space-y-1">
                    <p className="text-xs font-bold text-[#718096]">第二步：选择学术引擎</p>
                    <p className="text-[10px] text-[#a0aec0]">不同引擎在统计推理上各有侧重</p>
                  </div>
                  <div className="grid grid-cols-1 gap-3">
                    <button 
                      onClick={() => setSelectedModel('gemini-3-flash-preview')}
                      className="group flex items-center justify-between p-5 bg-[#f8fafc] border border-[#e2e8f0] rounded-2xl hover:border-[#9bb7d4] hover:bg-white transition-all"
                    >
                      <div className="text-left">
                        <p className="text-xs font-bold text-[#4a5568]">Gemini Flash 3</p>
                        <p className="text-[9px] text-[#a0aec0]">推荐用于快速数据解读</p>
                      </div>
                      <div className="w-6 h-6 rounded-full bg-white border border-[#e2e8f0] group-hover:bg-[#9bb7d4] transition-all flex items-center justify-center">
                        <svg className="w-3 h-3 text-[#e2e8f0] group-hover:text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M9 5l7 7-7 7"></path></svg>
                      </div>
                    </button>
                    <button 
                      onClick={() => setSelectedModel('deepseek-chat')}
                      className="group flex items-center justify-between p-5 bg-[#f8fafc] border border-[#e2e8f0] rounded-2xl hover:border-[#b8c6db] hover:bg-white transition-all"
                    >
                      <div className="text-left">
                        <p className="text-xs font-bold text-[#4a5568]">DeepSeek Chat</p>
                        <p className="text-[9px] text-[#a0aec0]">推荐用于深度理论探讨</p>
                      </div>
                      <div className="w-6 h-6 rounded-full bg-white border border-[#e2e8f0] group-hover:bg-[#b8c6db] transition-all flex items-center justify-center">
                        <svg className="w-3 h-3 text-[#e2e8f0] group-hover:text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M9 5l7 7-7 7"></path></svg>
                      </div>
                    </button>
                  </div>
                </div>
              ) : (
                // 第三步：正式提问
                <div className="flex-1 flex flex-col h-full animate-fade-in overflow-hidden">
                  <div className="flex-1 overflow-y-auto space-y-4 pr-1 scrollbar-hide mb-4 pt-2">
                    {chatHistory.length === 0 && (
                      <div className="space-y-3">
                        <p className="text-[10px] font-bold text-[#cbd5e0] uppercase tracking-widest">推荐学术提问：</p>
                        {["分析当前收敛性", "解释中心极限定理的应用"].map(q => (
                          <button key={q} onClick={() => handleAskAi(q)} className="w-full text-left text-[11px] p-3.5 bg-[#f8fafc] border border-[#e2e8f0] rounded-2xl hover:bg-white hover:border-[#9bb7d4] transition-all text-[#718096]">{q}</button>
                        ))}
                      </div>
                    )}
                    {chatHistory.map((m, i) => (
                      <div key={i} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                        <div className={`max-w-[90%] p-4 rounded-2xl text-xs leading-relaxed ${m.role === 'user' ? 'bg-[#9bb7d4] text-white rounded-tr-none shadow-sm' : 'bg-[#f0f4f8] text-[#4a5568] rounded-tl-none border border-[#e2e8f0] prose-sm'}`}>
                          {m.text}
                        </div>
                      </div>
                    ))}
                    {isAiLoading && (
                      <div className="flex items-center gap-2 p-4 text-[#a0aec0] animate-pulse">
                        <div className="w-1.5 h-1.5 bg-[#9bb7d4] rounded-full"></div>
                        <span className="text-[10px] font-bold">专家正在审阅实验报告...</span>
                      </div>
                    )}
                    <div ref={chatEndRef}></div>
                  </div>
                  <div className="pt-4 border-t border-[#f0f4f8] relative">
                    <input 
                      type="text" 
                      value={userInput} 
                      onChange={e => setUserInput(e.target.value)} 
                      onKeyDown={e => e.key === 'Enter' && handleAskAi()}
                      placeholder="咨询统计学者..." 
                      className="w-full bg-[#f8fafc] border border-[#e2e8f0] rounded-2xl px-5 py-4 text-xs outline-none focus:ring-2 focus:ring-[#9bb7d4]/20 pr-12"
                    />
                    <button onClick={() => handleAskAi()} className="absolute right-3 top-[30px] text-[#9bb7d4] hover:scale-110 transition-all">
                      <svg className="w-5 h-5" fill="currentColor" viewBox="0 0 20 20"><path d="M10.894 2.553a1 1 0 00-1.788 0l-7 14a1 1 0 001.169 1.409l5-1.429A1 1 0 009 15.571V11a1 1 0 112 0v4.571a1 1 0 00.725.962l5 1.428a1 1 0 001.17-1.408l-7-14z"></path></svg>
                    </button>
                  </div>
                </div>
              )}
            </div>
            {/* 背景装饰 */}
            <div className="absolute top-[-50%] left-[-50%] w-[200%] h-[200%] bg-gradient-to-br from-[#f8fafc] via-transparent to-[#f0f4f8] opacity-50 pointer-events-none"></div>
          </div>
        </aside>

        {/* 右侧主视窗 */}
        <section className="lg:col-span-8 space-y-8">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <DistributionChart data={parentData} title="总体概率密度分布" color="#a0aec0" />
            <DistributionChart data={samplingMeans} title={`抽样分布 (n=${sampleSize})`} color="#9bb7d4" />
          </div>

          <div className="bg-white p-8 rounded-[2.5rem] shadow-sm border border-white/50">
            <div className="flex justify-between items-center mb-10">
              <h3 className="text-xs font-bold text-[#cbd5e0] uppercase tracking-[0.3em]">统计学摘要 (Summary)</h3>
              <div className="flex gap-4">
                <span className="text-[10px] font-mono text-[#a0aec0]">μ₀: {theoretical.mu.toFixed(2)}</span>
                <span className="text-[10px] font-mono text-[#a0aec0]">σ₀: {theoretical.sigma.toFixed(2)}</span>
              </div>
            </div>

            <div className="grid grid-cols-1 sm:grid-cols-3 gap-12">
              <div className="space-y-1">
                <p className="text-[10px] font-bold text-[#cbd5e0] uppercase">观测均值 X̄</p>
                <p className="text-4xl font-black text-[#2d3748] font-mono tracking-tighter">{stats.mean.toFixed(4)}</p>
              </div>
              <div className="space-y-1">
                <p className="text-[10px] font-bold text-[#cbd5e0] uppercase">观测标准误 SE</p>
                <p className="text-4xl font-black text-[#9bb7d4] font-mono tracking-tighter">{stats.std.toFixed(4)}</p>
              </div>
              <div className="space-y-1">
                <p className="text-[10px] font-bold text-[#cbd5e0] uppercase">正态拟合度</p>
                <div className="flex items-center gap-3">
                  <p className={`text-3xl font-black tracking-tighter ${sampleSize >= 30 ? 'text-[#a7c1d1]' : 'text-[#d9c5b2]'}`}>
                    {sampleSize >= 100 ? '极高' : sampleSize >= 30 ? '显著' : '微弱'}
                  </p>
                  <div className="h-2 w-16 bg-[#f0f4f8] rounded-full overflow-hidden">
                    <div className="h-full bg-[#9bb7d4] transition-all" style={{width: `${Math.min(100, (sampleSize/50)*100)}%`}}></div>
                  </div>
                </div>
              </div>
            </div>

            {/* 置信区间覆盖监测 - 淡雅配色 */}
            <div className="mt-12 pt-8 border-t border-[#f0f4f8]">
              <div className="flex justify-between items-center mb-5">
                <h4 className="text-[10px] font-bold text-[#a0aec0] uppercase flex items-center gap-2">
                  <div className="w-2 h-2 bg-[#b8c6db] rounded-full"></div> 95% 置信区间覆盖监测
                </h4>
                <div className="text-[10px] font-bold text-[#718096]">
                  捕获率: <span className={ciSuccessCount >= 90 ? 'text-[#9bb7d4]' : 'text-[#d9c5b2]'}>{ciSuccessCount}%</span>
                </div>
              </div>
              <div className="h-12 w-full bg-[#f8fafc] rounded-2xl flex items-center gap-[1px] px-3 border border-[#e2e8f0] overflow-hidden shadow-inner">
                {ciData.map((d, i) => (
                  <div key={i} className="flex-1 flex flex-col items-center justify-center h-full">
                    <div className={`w-full ${d.contains ? 'bg-[#9bb7d4]/30' : 'bg-[#d9c5b2]/60'} rounded-full`} style={{ height: '30%' }}></div>
                  </div>
                ))}
              </div>
              <p className="mt-4 text-[11px] text-[#a0aec0] font-medium leading-relaxed italic text-center">
                “ 随着样本量 n 的增加，均值的分布逐渐从混沌回归秩序。”
              </p>
            </div>
          </div>

          <TheoryModule />

          <footer className="text-center py-12 text-[10px] font-bold text-[#cbd5e0] uppercase tracking-[0.5em]">
            Stochastic Intelligence Lab · Senior Education Project
          </footer>
        </section>
      </main>
    </div>
  );
};

export default App;

